const inboxes = Array.isArray($input.first().json) ? $input.first().json : [];
const domains = [...new Set(inboxes.map(i => (i.from_email || i.email || '').split('@')[1]).filter(Boolean))];
const blocked = inboxes.filter(i => !i.is_smtp_success || i.warmup_details?.is_warmup_blocked);

return domains.map(domain => ({
  json: {
    domain,
    inbox_count: inboxes.filter(i => (i.from_email || i.email || '').endsWith('@' + domain)).length,
    blocked_count: inboxes.filter(i => (i.from_email || i.email || '').endsWith('@' + domain) && (!i.is_smtp_success || i.warmup_details?.is_warmup_blocked)).length
  }
}));

const domain = $('Extract Unique Domains').item.json;
const spf = $('Check SPF (DNS)').item.json;
const dmarc = $('Check DMARC (DNS)').item.json;

function hasTxt(records, needle) {
  const answers = records?.Answer || [];
  return answers.some(a => (a.data || '').includes(needle));
}

const spfOk = hasTxt(spf, 'v=spf1');
const dmarcOk = hasTxt(dmarc, 'v=DMARC1');
let score = 100;
if (!spfOk) score -= 40;
if (!dmarcOk) score -= 30;

const issues = [];
if (!spfOk) issues.push('SPF missing');
if (!dmarcOk) issues.push('DMARC missing');
if (domain.blocked_count > 0) issues.push(domain.blocked_count + ' blocked inboxes');

return [{
  json: {
    domain: domain.domain,
    inbox_count: domain.inbox_count,
    spf_present: spfOk,
    dmarc_present: dmarcOk,
    auth_score: score,
    issues: issues.join('; ') || 'OK',
    flag: score < 80 || domain.blocked_count > 0
  }
}];

const campaigns = Array.isArray($input.first().json) ? $input.first().json : [];
const active = campaigns.filter(c => ['ACTIVE','PAUSED','COMPLETED'].includes(c.status));
return active.map(c => ({ json: { campaign_id: c.id, campaign_name: c.name, status: c.status } }));

const meta = $('Filter Active Campaigns').item.json;
const stats = $input.first().json;
const sent = parseInt(stats.sent_count || stats.total_sent || 0);
const replies = parseInt(stats.reply_count || stats.total_replied || 0);
const replyRate = sent > 0 ? Math.round((replies / sent) * 10000) / 100 : 0;
const flag = sent >= 200 && replyRate < 1.0;
return [{ json: {
  campaign_name: meta.campaign_name,
  sent, replies, reply_rate_pct: replyRate,
  flag_low_reply: flag,
  message: flag ? `BELOW 1% RULE: ${replyRate}% reply after ${sent} sends` : 'OK'
}}];

const domainIssues = $('Score Domain Auth').all().filter(i => i.json.flag);
const campaignIssues = $('Check 1% Reply Rule').all().filter(i => i.json.flag_low_reply);

const lines = ['*Weekly Deliverability Audit*', ''];
lines.push(`Domain issues: ${domainIssues.length}`);
domainIssues.forEach(i => lines.push(`- ${i.json.domain}: ${i.json.issues} (score ${i.json.auth_score})`));
lines.push('');
lines.push(`Campaigns below 1% rule: ${campaignIssues.length}`);
campaignIssues.forEach(i => lines.push(`- ${i.json.campaign_name}: ${i.json.reply_rate_pct}% (${i.json.sent} sent)`));

if (domainIssues.length === 0 && campaignIssues.length === 0) {
  lines.push('', 'All clear. No action needed.');
}

return [{ json: { slack_text: lines.join('\n'), domain_issues: domainIssues.length, campaign_issues: campaignIssues.length } }];
